Here's the code for the `/ban` command:
```javascript
const { SlashCommandBuilder } = require('discord.js');

module.exports = {
  data: new SlashCommandBuilder()
    .setName('ban')
    .setDescription('Bans a user from the server.')
    .addUserOption(option => option.setName('user').setDescription('The user to ban.'))
    .addStringOption(option => option.setName('reason').setDescription('The reason for the ban.').setRequired(false)),
  async execute(interaction) {
    const user = interaction.options.getUser('user');
    const reason = interaction.options.getString('reason') || 'No reason provided.';

    if (!interaction.member.permissions.has('BanMembers')) {
      return interaction.reply({ content: 'You do not have permission to use this command.', ephemeral: true });
    }

    if (!user) {
      return interaction.reply({ content: 'Please provide a user to ban.', ephemeral: true });
    }

    if (user.id === interaction.user.id) {
      return interaction.reply({ content: 'You cannot ban yourself.', ephemeral: true });
    }

    if (user.id === interaction.guild.ownerId) {
      return interaction.reply({ content: 'You cannot ban the server owner.', ephemeral: true });
    }

    try {
      await interaction.guild.members.ban(user, { reason: reason });
      interaction.reply({ content: `Successfully banned ${user.tag}.`, ephemeral: true });
    } catch (error) {
      console.error(error);
      interaction.reply({ content: 'There was an error trying to ban that user.', ephemeral: true });
    }
  },
};
